    fig, axs = plt.subplots(1,3, figsize=(15, 5))
    pdf = np.array(pdf)
    histogram = np.array(histogram)
    diff=histogram - pdf
    absdiff=np.abs(diff).max()
    a = pdf.shape[1] / pdf.shape[0]
    pdf_plot = axs[0].imshow(pdf, vmin=0, aspect=a, interpolation='nearest')
    hist_plot = axs[1].imshow(histogram, vmin=0, aspect=a, interpolation='nearest')
    diff_plot = axs[2].imshow(diff, aspect=a, vmin=-absdiff, vmax=absdiff, interpolation='nearest', cmap='coolwarm')
    axs[0].title.set_text('PDF')
    axs[1].title.set_text('Histogram')
    axs[2].title.set_text('Difference')
    props = dict(fraction=0.046, pad=0.04)
    fig.colorbar(pdf_plot, ax=axs[0], **props)
    fig.colorbar(hist_plot, ax=axs[1], **props)
    fig.colorbar(diff_plot, ax=axs[2], **props)
    plt.tight_layout()
    plt.show()
